using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

/// <summary>
/// Shared helper methods for creating in-memory SchoolContext instances and draining the notification queue.
/// </summary>
internal static class TestHelpers
{
    public static SchoolContext CreateContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(dbName)
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Drain the static NotificationService queue to prevent cross-test contamination.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        var svc = new Services.NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    public static void SeedStudents(SchoolContext ctx)
    {
        ctx.Students.AddRange(
            new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2019-09-01") },
            new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2017-09-01") },
            new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2018-09-01") }
        );
        ctx.SaveChanges();
    }

    public static void SeedDepartmentsAndCourses(SchoolContext ctx)
    {
        var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000m, StartDate = DateTime.Parse("2019-01-01") };
        ctx.Departments.Add(dept);
        ctx.SaveChanges();

        ctx.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1 }
        );
        ctx.SaveChanges();
    }

    public static void SeedInstructors(SchoolContext ctx)
    {
        ctx.Instructors.AddRange(
            new Instructor { ID = 10, LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() },
            new Instructor { ID = 11, LastName = "Harui", FirstMidName = "Roger", HireDate = DateTime.Parse("1998-07-01"), CourseAssignments = new List<CourseAssignment>() }
        );
        ctx.SaveChanges();
    }
}

