    [DataRow("Smith", "Jane", "Smith, Jane", DisplayName = "Another name")]
    [DataRow("", "", ", ", DisplayName = "Empty name parts")]
    public void FullName_ConcatenatesLastAndFirst(string last, string first, string expected)
