namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _ctx;
    private NotificationsController _sut;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _ctx = TestHelpers.CreateContext();
        _sut = new NotificationsController(_ctx);
        _sut.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _sut.TempData = new TempDataDictionary(
            _sut.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
        _sut.Dispose();
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsEmptyList()
    {
        var result = _sut.GetNotifications();

        Assert.IsNotNull(result);
        var json = result.Value as dynamic;
        Assert.IsNotNull(json);
    }

    [TestMethod]
    public void GetNotifications_WithItems_ReturnsNotifications()
    {
        var svc = new Services.NotificationService();
        svc.SendNotification("Student", "1", EntityOperation.CREATE);
        svc.SendNotification("Course", "2", EntityOperation.UPDATE);

        var result = _sut.GetNotifications();

        Assert.IsNotNull(result);
        // Verify it's a JsonResult
        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        var svc = new Services.NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        var result = _sut.GetNotifications();

        Assert.IsNotNull(result);
        // After dequeuing max 10, there should be 5 remaining
        int remaining = 0;
        while (svc.ReceiveNotification() != null) remaining++;
        Assert.AreEqual(5, remaining);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        var result = _sut.MarkAsRead(1);

        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _sut.Index() as ViewResult;
        Assert.IsNotNull(result);
    }
}

